using namespace std;

long long solve(std::string s, std::vector<long long> order, long long k) {
    int n = s.size();
    unordered_set<int> starred_indices;
    long long total = 0;

    for (long long t = 0; t < n; ++t) {
        int idx = order[t];
        if (s[idx] != '*') {
            // Calculate the number of new valid substrings introduced by this '*'
            // The new '*' is at position idx
            // The valid substrings are those that include this '*'
            // The number is (idx + 1) * (n - idx) - existing overlaps
            // But need to subtract those already counted in previous '*'s

            // To avoid double-counting, we need to find the left and right boundaries
            // where there are no '*'s adjacent to the current one
            int left = idx;
            while (left > 0 && s[left - 1] != '*' && starred_indices.find(left - 1) == starred_indices.end()) {
                --left;
            }
            int right = idx;
            while (right < n - 1 && s[right + 1] != '*' && starred_indices.find(right + 1) == starred_indices.end()) {
                ++right;
            }

            // The number of new substrings is (idx - left + 1) * (right - idx + 1)
            long long new_substrings = (idx - left + 1) * (right - idx + 1);
            total += new_substrings;

            if (total >= k) {
                return t;
            }

            // Mark this index as starred
            s[idx] = '*';
            starred_indices.insert(idx);
        }
    }

    return -1;
}

